// Validate input — webhook v1.1 wraps POST body under $json.body
const data = $json.body || $json;
if (!data.tenantId || !data.areaCode) {
  throw new Error('Missing tenantId or areaCode');
}

// Texas area codes fallback list
const TX_AREA_CODES = ['512', '737', '210', '214', '972', '469', '817', '682', '281', '832', '713', '346', '361', '915', '806', '903', '936', '956'];

const primaryAreaCode = data.areaCode;
const fallbacks = TX_AREA_CODES.filter(c => c !== primaryAreaCode).slice(0, 3);

return [{
  json: {
    tenantId: data.tenantId,
    areaCode: primaryAreaCode,
    fallbackAreaCodes: fallbacks,
    shopName: data.shopName || 'AutoShop',
    attempt: 0,
  }
}];

// TODO: Send welcome email via email provider (SendGrid/Resend)
// Include: assigned phone number, setup instructions, dashboard link
console.log('TODO: Send welcome email to tenant:', $('Validate + Prepare').first().json.tenantId);
console.log('Assigned number:', $('Twilio: Purchase Number').first().json.phone_number);
return [{ json: { status: 'provisioned', number: $('Twilio: Purchase Number').first().json.phone_number } }];

// No numbers available in requested area code
// TODO: Alert admin via Slack/email for manual resolution
console.error('No numbers available for area code:', $('Validate + Prepare').first().json.areaCode);
console.error('Tenant:', $('Validate + Prepare').first().json.tenantId);

// TODO: Update tenant record with provisioning_status = 'failed'
// TODO: Send alert to admin

return [{ json: { status: 'failed', reason: 'no_numbers_available' } }];
